script:
frappe.ui.form.on('VM Job Card', {
    before_save(frm) {
        frm.doc.vmjc_part_total = frm.doc.vmjc_part_rate * frm.doc.vmjc_part_quantity;
	},

	onload(frm) {
	},

	on_submit(frm) {
	    // Create a Stock Entry on Submit
	},

	after_cancel(frm) {
	    // Delete the stock Entry created; linked in hidden field
	},

	vmjc_job(frm) {
        frappe.call({
            method: "get_last_vmjc",
            args: {
                'data': frm.doc
            },
            callback: function(data) {
                if(data) {
                    if (data.last_date)
                        frm.set_value('vmjc_last_service_date', data.last_date);
                    if (data.last_vmjc_ref)
                        frm.set_value('vmjc_last_vmjc_ref', data.last_vmjc_ref);
                    if (data.last_part_date)
                        frm.set_value('vmjc_last_service_date', data.last_part_date);
                    if (data.last_part_vmjc_ref)
                        frm.set_value('vmjc_last_vmjc_ref', data.last_part_vmjc_ref);
                }
            }
        });
	},

	vmjc_spare_part(frm) {
        frappe.call({
            method: "get_last_vmjc",
            args: {
                'data': frm.doc
            },
            callback: function(data) {
                if(data) {
                    if (data.last_date)
                        frm.set_value('vmjc_last_service_date', data.last_date);
                    if (data.last_vmjc_ref)
                        frm.set_value('vmjc_last_vmjc_ref', data.last_vmjc_ref);
                    if (data.last_part_date)
                        frm.set_value('vmjc_last_service_date', data.last_part_date);
                    if (data.last_part_vmjc_ref)
                        frm.set_value('vmjc_last_vmjc_ref', data.last_part_vmjc_ref);
                }
            }
        });
	}
})

frappe.ui.form.on('Vehicle', {
	refresh(frm) {
        frappe.call({
            method: "datatable_vehicle_maintenance_record",
            args: {
                'data': frm.doc
            },
            callback: function(data) {
                if(data) {
                    const datatable = new DataTable('*[data-fieldname="custom_vmr_datatables"]', {
                        columns: data.columns,
                        data: data.data
                      });
                }
            }
        });
        frappe.call({
            method: "datatable_vehicle_maintenance_schedule",
            args: {
                'data': frm.doc
            },
            callback: function(data) {
                if(data) {
                    const datatable = new DataTable('*[data-fieldname="custom_vms_datatables"]', {
                        columns: data.columns,
                        data: data.data
                      });
                }
            }
        });

	}
})

frappe.ui.form.on('Vehicle Maintenance Record', {
	refresh(frm) {
		frappe.call({
            method: "datatable_vm_job_card",
            args: {
                'data': frm.doc
            },
            callback: function(data) {
                if(data) {
                    const datatable = new DataTable('*[data-fieldname="vm_job_card_datatable"]', {
                        columns: data.columns,
                        data: data.data,
                        get_row_data: (row) => {
                            // Define action button click behavior
                            row.action = $('<button class="btn btn-default btn-sm">View Details</button>').on('click', function() {
                                var docname = row.name;
                                frappe.set_route('Form', 'VM Job Card', docname);
                            });
                            return row;
                        }
                      });
                }
            }
        });
	}
})
